(function(global) {
  'use strict';
  
  // 检查是否已经从 CDN 加载了 jsPDF
  if (global.jspdf && global.jspdf.jsPDF) {
    console.log('📄 jsPDF 已从 CDN 加载');
    return;
  }
  
  // 显示提示消息
  console.warn('⚠️ jsPDF 库未找到，请从以下地址下载：https://cdnjs.cloudflare.com/ajax/libs/jspdf/2.5.1/jspdf.umd.min.js');
  console.warn('将下载的内容保存到 libs/jspdf.min.js 文件');
  
})(typeof window !== 'undefined' ? window : this);